VALUES
  ('elementary-8b44517b-moex-00957', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '有關親屬之親系與親等之規定，對於自己與繼母之表兄的親系與親等，下列敘述何者正確？', '["無親屬關係", "旁系姻親三親等", "旁系姻親四親等", "旁系姻親五親等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00958', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於民法規定正當防衛、緊急避難與自助行為之敘述，下列何者正確？', '["因避免自己之生命身體受到急迫危險所為之自助行為，致他人財產受新臺幣50萬元以下之損害者，不 負賠償責任", "因避免自己之配偶、或直系血親三親等內之親屬，受到身體或自由上之急迫危險所為之家族集體自助 行為，致生他人之生命身體或財產損害者，不負賠償責任", "對於現時或24小時內已發生之不法的人身侵害，為防衛自己、配偶或家屬之權利所為的行為，不負損 害賠償之責", "為保護自己權利，對於他人之自由或財產施以拘束、押收或毀損者，不負損害賠償之責。但以不及受 法院或其他有關機關援助，並非於其時為之，則請求權不得實行或其實行顯有困難者為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00959', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依現行民法之規定，19歲之甲因很想購買全新機車，擅自將父親乙贈與之老舊A機車拋棄。甲對A機車 之拋棄行為效力如何？', '["有效，不得撤銷", "無效", "效力未定", "有效，得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00960', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲欲購買乙的二手筆記型電腦，交付新臺幣（下同）5,000元定金予乙，約定5日後交貨。關於定金之敘 述，下列何者錯誤？', '["甲交付定金予乙，依民法規定，乙受有定金時，推定其契約成立", "若甲於交付定金後，現場檢視該筆電時，不慎摔毀該筆電，則甲不得請求返還定金", "若乙交付筆電前，不慎摔毀該筆電，則乙應返還1萬元給甲", "若乙交付筆電前，筆電因無名火而燒燬，甲不得請求返還定金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00961', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於保證之敘述，下列何者錯誤？', '["保證人之負擔較主債務人為重者，應縮減至主債務之限度", "債權人未就主債務人之財產強制執行而無效果前，且未有喪失先訴抗辯權之事由，保證人對於債權人 得拒絕清償", "主債務人所有之抗辯，保證人均得主張", "保證人對於因欠缺行為能力而無效之債務，縱使知其情事而為保證，該保證仍因從屬性而無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00962', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於不動產物權行為之敘述，下列何者錯誤？', '["要式行為", "非經登記，不生效力", "非經交付標的物，不生效力", "債權行為無效、不成立或被撤銷者，不影響不動產物權行為效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00963', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者非屬最高限額抵押權所擔保原債權之法定確定事由？', '["擔保債權之範圍變更或因其他事由，致原債權不繼續發生者", "最高限額抵押權所擔保之債權，其請求權已因時效而消滅", "最高限額抵押權人聲請裁定拍賣抵押物", "債務人或抵押人經裁定宣告破產確定者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00964', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '甲男乙女為夫妻，有丙、丁二子。丙有戊、己二子。丙先於甲死亡。甲死亡時，戊依法拋棄繼承。己之 應繼分為何？', '["三分之一", "四分之一", "五分之一", "六分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00965', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於刑事訴訟法第155條第2項所定「無證據能力、未經合法調查之證據，不得作為判斷之依據。」下 列敘述何者正確？', '["這是證據之證明力的規定", "證據能力是由法院本於確信自由判斷", "這是關於嚴格證明的規定", "只要經過合法調查的證據資料，均有證據能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00966', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '檢察官以被告甲在警詢中自白、購毒者乙在偵查中之證言等證據，起訴甲販賣毒品罪。甲在第一審受命 法官準備程序期日，陳述其在警詢時之自白，是被強暴脅迫所為，下列何人要就甲在警詢中係出於自由 意志之自白，指出證明方法？', '["甲", "檢察官", "法官", "乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
